package main

import (
	"fmt"
	"strings"
)

// SumAbsoluteValues returns the sum of absolute values of nonzero integers,
// and optionally a formatted string listing each nonzero value.
// Positive values appear as "N,"; negative as "(N),".
// Returns an error if the sum is zero (no nonzero values).
func SumAbsoluteValues(values []int, label string, includeFormat bool) (int, string, error) {
	sum := 0
	var formatted strings.Builder
	for _, v := range values {
		if v > 0 {
			sum += v
		} else if v < 0 {
			sum += -v
		}
		if v != 0 && includeFormat {
			formatted.WriteString(formatValue(v))
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	result := formatted.String()
	if label != "" {
		result = label + ": " + result
	}
	return sum, result, nil
}

// formatValue returns the formatted representation of a nonzero value.
func formatValue(v int) string {
	if v > 0 {
		return fmt.Sprintf("%d,", v)
	}
	return fmt.Sprintf("(%d),", v)
}

package pkg

import (
	"fmt"
	"strings"
)

// processNumbers computes the sum of absolute values of non-zero elements
// and optionally builds a formatted detail string. Returns an error when the
// sum is zero (e.g. empty input or all zeros).
func processNumbers(numbers []int, label string, includeDetails bool) (int, string, error) {
	sum := 0
	var details strings.Builder

	for _, n := range numbers {
		if n > 0 {
			sum += n
			if includeDetails {
				details.WriteString(fmt.Sprintf("%d,", n))
			}
		} else if n < 0 {
			sum += -n
			if includeDetails {
				details.WriteString(fmt.Sprintf("(%d),", n))
			}
		}
	}

	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}

	result := details.String()
	if label != "" {
		result = label + ": " + result
	}
	return sum, result, nil
}

// sumAbsoluteValuesAndFormat computes the sum of absolute values of non-zero
// elements, optionally builds a formatted string, and returns an error when
// the sum is zero.
func sumAbsoluteValuesAndFormat(numbers []int, label string, includeFormatting bool) (int, string, error) {
	sum := 0
	var formattedParts []string

	for _, n := range numbers {
		if n > 0 {
			sum += n
			if includeFormatting {
				formattedParts = append(formattedParts, fmt.Sprintf("%d,", n))
			}
		} else if n < 0 {
			sum -= n // adds |n| to sum
			if includeFormatting {
				formattedParts = append(formattedParts, fmt.Sprintf("(%d),", n))
			}
		}
	}

	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}

	var result string
	if includeFormatting {
		result = strings.Join(formattedParts, "")
		if label != "" {
			result = label + ": " + result
		}
	}

	return sum, result, nil
}

func SumPositiveAndNegative(values []int, label string, includeDetails bool) (int, string, error) {
	sum, details := computeSumAndDetails(values, includeDetails)
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if label != "" {
		details = label + ": " + details
	}
	return sum, details, nil
}

func computeSumAndDetails(values []int, includeDetails bool) (int, string) {
	var sum int
	var details strings.Builder
	for _, v := range values {
		if v > 0 {
			sum += v
			if includeDetails {
				details.WriteString(fmt.Sprintf("%d,", v))
			}
		} else if v < 0 {
			sum -= v
			if includeDetails {
				details.WriteString(fmt.Sprintf("(%d),", v))
			}
		}
	}
	return sum, details.String()
}
